import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListResourcesRequestSchema,
  ListToolsRequestSchema,
  ReadResourceRequestSchema
} from "@modelcontextprotocol/sdk/types.js";
import pg from "pg";

const { Pool } = pg;

// Initialize db pool using environment configuration
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  statement_timeout: 500 // Enforce statement execution limits
});

const server = new Server(
  {
    name: "secure-postgres-mcp",
    version: "1.0.0"
  },
  {
    capabilities: {
      resources: {},
      tools: {}
    }
  }
);

// Expose dynamic schema as resource
server.setRequestHandler(ListResourcesRequestSchema, async () => {
  return {
    resources: [
      {
        uri: "postgres://schema/customer_summary",
        name: "Customer Summary Table Schema",
        mimeType: "application/json",
        description: "Schema layout and columns of the customer_summary table"
      }
    ]
  };
});

// Read schema metadata
server.setRequestHandler(ReadResourceRequestSchema, async (request) => {
  if (request.params.uri === "postgres://schema/customer_summary") {
    const res = await pool.query(
      "SELECT column_name, data_type FROM information_schema.columns WHERE table_name = 'customer_summary'"
    );
    return {
      contents: [
        {
          uri: request.params.uri,
          mimeType: "application/json",
          text: JSON.stringify(res.rows)
        }
      ]
    };
  }
  throw new Error("Resource not found");
});

// Register query tool
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "query_customer_data",
        description: "Queries safe customer details by customer ID",
        inputSchema: {
          type: "object",
          properties: {
            customerId: {
              type: "integer",
              description: "Customer ID"
            }
          },
          required: ["customerId"]
        }
      }
    ]
  };
});

// Handle execution safely via parameterized inputs
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === "query_customer_data") {
    const customerId = request.params.arguments?.customerId;
    if (typeof customerId !== "number") {
      throw new Error("Invalid customerId input parameter type");
    }

    const res = await pool.query(
      "SELECT id, name, email, region FROM customer_summary WHERE id = $1 LIMIT 1",
      [customerId]
    );

    return {
      content: [
        {
          type: "text",
          text: JSON.stringify(res.rows)
        }
      ]
    };
  }
  throw new Error("Tool not found");
});

const transport = new StdioServerTransport();
await server.connect(transport);
